INSERT INTO selection_items (id, slug, type, category, title, label, price_text, affiliate_text, reason, fit_for, notice, image_url, rating_text, review_count_text, is_highlighted, external_url, status, sort_order) VALUES
    ('c1000000-0000-0000-0000-000000000001', 'frosch-washer-cleaner', 'product', '세탁/침구', '프로쉬 세탁조 클리너 250g', '세탁조', '약 8,500~11,900원', '쿠팡/마켓컬리', 'pH 2.6 산성 타입으로 세탁기 호스와 배수펌프에 쌓인 물때, 찌든 때, 석회질을 관리하는 세탁조 클리너', '오랫동안 세탁조를 청소하지 않았거나 세탁기에서 냄새가 날 때', '통돌이/드럼 겸용 여부와 사용 후 헹굼 횟수는 제품 안내를 확인하세요.', '/cleanloop/images/selection-frosch-washer-cleaner.png', '4.7', '후기 1,174개', TRUE, 'https://www.coupang.com/vp/products/6489234192', 'published', 10),
    ('c1000000-0000-0000-0000-000000000002', 'downy-unstopables-ocean', 'product', '세탁/침구', '다우니 언스탑퍼블 오션미스트 1.13kg', '향기부스터', '약 30,990원', '11번가/코스트코', '세탁 시 세제와 함께 넣는 알갱이형 향기 지속제로 실내건조 냄새와 잔향 관리에 쓰기 좋은 세탁 보조제', '세탁 후 향이 오래 지속되길 원하거나 실내건조 냄새가 신경 쓰일 때', '향 종류와 묶음 수량에 따라 가격 차이가 큽니다.', '/cleanloop/images/selection-downy-unstopables-ocean.png', '4.6', '후기 100개', FALSE, 'https://www.11st.co.kr/products/1323262484', 'published', 11),
    ('c1000000-0000-0000-0000-000000000003', 'washswat-bedding', 'service', '세탁/침구', '세탁특공대 이불 세탁 서비스', '이불세탁', '공식 가격표 확인', '세탁특공대', '모바일로 신청하면 대형 이불을 집 앞에서 수거해 세탁, 건조 후 다시 배송하는 비대면 세탁 서비스', '집 세탁기로 감당하기 어려운 대형 이불을 들고 나가지 않고 처리하고 싶을 때', '거주 지역과 세탁 불가 소재를 예약 전 확인하세요.', '/cleanloop/images/selection-washswat-bedding.png', '확인 안 됨', '공식 가격표 기준', TRUE, 'https://www.getwashswat.com/price', 'published', 12),
    ('c1000000-0000-0000-0000-000000000004', 'homestar-mold-spray', 'product', '욕실', '홈스타 뿌리는 곰팡이 싹 750ml', '곰팡이', '약 11,000~21,000원', '쿠팡/LG생활건강', '염소계 표백 성분의 거품이 타일 줄눈과 실리콘 틈새에 붙어 검은 곰팡이를 제거하는 욕실 세정제', '타일 줄눈이나 실리콘 코킹에 생긴 검은 곰팡이를 정기적으로 제거할 때', '반드시 환기하고 고무장갑을 착용하세요. 금속과 색 있는 실리콘은 먼저 테스트하세요.', '/cleanloop/images/selection-homestar-mold-spray.png', '4.5', '후기 53,779개', TRUE, 'https://www.lgcaremall.com/product/detail/S10002218', 'published', 13),
    ('c1000000-0000-0000-0000-000000000005', 'okong-bath-silicone', 'product', '욕실', '오공 욕실용 바이오 실리콘 실란트 SS710', '욕실보수', '약 3,000~5,400원', '시트라인/건재몰', '항균 성분을 더한 욕실, 싱크대, 세면대용 실리콘 코킹재로 습한 공간의 곰팡이 발생을 줄이는 보수용품', '욕조나 세면대 실리콘 코킹이 갈라지거나 검게 변색되어 재시공이 필요할 때', '실리콘건 등 시공 도구와 색상 옵션을 확인하세요.', '/cleanloop/images/selection-okong-bath-silicone.png', '확인 안 됨', '판매처별 상이', FALSE, 'https://www.sheetline.co.kr/', 'published', 14),
    ('c1000000-0000-0000-0000-000000000006', 'miso-homeclean-doc', 'service', '욕실', '미소 가사도우미 홈클린 서비스', '방문청소', '2시간 34,900원부터', '미소', '가사도우미가 방문해 욕실, 주방, 세탁, 정리를 2~8시간 단위로 제공하는 방문형 홈클리닝 서비스', '일상적인 욕실 청소를 정기적으로 맡기고 싶을 때', '곰팡이, 찌든 때, 물때 전문청소와 소독, 방충, 방역은 기본 범위에서 제외될 수 있습니다.', '/cleanloop/images/selection-miso-homeclean.png', '확인 안 됨', '앱 예약 기준', FALSE, 'https://miso.kr/homeclean', 'published', 15),
    ('c1000000-0000-0000-0000-000000000007', 'naum-tpu-cutting-board', 'product', '주방', '나움 모먼트 TPU 도마세트', '도마세트', '약 49,900원', '오늘의집', '99.9% 항균 TPU 재질 도마 4장과 스탠드 구성으로 육류, 생선, 채소, 과일 용도를 나눠 쓰기 좋습니다.', '도마를 용도별로 분리해 교차오염을 줄이고 싶은 1~2인 가구', '식기세척기 사용 가능 여부와 조리대 크기를 확인하세요.', '/cleanloop/images/selection-naum-tpu-cutting-board.png', '4.8', '후기 577개', TRUE, 'https://ohou.se/store/category?category_id=16310002', 'published', 16),
    ('c1000000-0000-0000-0000-000000000008', 'scotchbrite-antibacterial-sponge', 'product', '주방', '3M 스카치브라이트 항균 스펀지 다목적수세미', '수세미', '20개입 12,000원', '3M스토어', '항균 처리된 스펀지형 다목적 수세미로 설거지용 스펀지를 짧은 주기로 교체하며 위생 관리하기 좋습니다.', '설거지용 수세미를 정기적으로 교체하고 싶은 집', '구성, 개수, 사이즈가 판매처마다 다릅니다.', '/cleanloop/images/selection-scotchbrite-sponge.png', '확인 안 됨', '판매처별 상이', FALSE, 'https://3mstore.co.kr/category/%EC%88%98%EC%84%B8%EB%AF%B8/36/', 'published', 17),
    ('c1000000-0000-0000-0000-000000000009', 'haatz-hood-cleaner', 'product', '주방', '하츠 판클리너 렌지후드 필터 세정제', '후드필터', '약 7,880~15,760원', '미소홈/SSG', '렌지후드 필터망 전용 세정제로 정해진 비율로 희석해 필터를 담가 기름때를 제거합니다.', '렌지후드 사용시간 알림이 뜨거나 일반 세제로 안 빠지는 기름때가 눌어붙었을 때', '자사 필터 전용 설계라 타 브랜드 필터는 변색 위험이 있습니다.', '/cleanloop/images/selection-haatz-hood-cleaner.png', '확인 안 됨', '판매처별 상이', FALSE, 'https://misohome.net/', 'published', 18),
    ('c1000000-0000-0000-0000-000000000010', 'oneul-pickup-doc', 'service', '쓰레기/수거', '오늘수거 비대면 쓰레기 수거', '비대면수거', '100g당 약 140원', '오늘수거', '전용 비닐에 담아 문 앞에 내놓으면 밤 10시 이후 비대면으로 수거하는 당일 쓰레기 수거 서비스', '분리수거장이 멀거나 야간에 쓰레기를 직접 버리기 번거로운 1인 가구와 자취생', '서울, 수도권 중심 서비스이며 무게 기준 요금이라 배출량이 많으면 비용이 늘 수 있습니다.', '/cleanloop/images/selection-oneul-pickup.png', '확인 안 됨', '앱 소개 기준', TRUE, 'https://apps.apple.com/kr/app/id1606684132', 'published', 19),
    ('c1000000-0000-0000-0000-000000000011', 'cuckoo-ecowhale', 'product', '쓰레기/수거', '쿠쿠 에코웨일 음식물처리기 CFD-ENL201DCGW', '음식물처리기', '약 38만~46만원대', '쿠쿠/11번가', '분쇄와 열풍건조 방식으로 음식물쓰레기를 감량하고 탈취하는 2L 용량 가정용 음식물처리기', '음식물쓰레기 냄새와 배출 부피, 배출 횟수를 줄이고 싶은 가정', '탈취필터 교체 비용, 설치 공간, 소비전력을 확인하세요.', '/cleanloop/images/selection-cuckoo-ecowhale.png', '확인 안 됨', '공식몰 후기 207건', FALSE, 'https://www.cuckoo.co.kr/', 'published', 20),
    ('c1000000-0000-0000-0000-000000000012', 'parisien-food-bin', 'product', '쓰레기/수거', '파리지앵 진공 음식물쓰레기통 3L', '냄새차단', '약 15,300원', '쿠팡', '뚜껑을 닫으면 냄새를 차단하는 진공 밀폐 방식의 3L 소형 음식물쓰레기통', '별도 가전제품 없이 저렴하게 음식물쓰레기 냄새를 줄이고 싶은 1~2인 가구', '용량이 작아 배출 주기가 잦아질 수 있습니다.', '/cleanloop/images/selection-parisien-food-bin.png', '4.5', '후기 768개', FALSE, 'https://www.coupang.com/vp/products/7563436738', 'published', 21),
    ('c1000000-0000-0000-0000-000000000013', 'comet-spray-mop', 'product', '바닥/먼지', '코멧 스프레이 밀대걸레 세트', '물걸레', '약 11,600~12,890원', '쿠팡', '스프레이 분사 기능과 360도 회전 헤드, 극세사 패드가 포함된 물걸레 밀대 세트', '별도 세제 스프레이 없이 밀대 하나로 물걸레질까지 끝내고 싶을 때', '밀대 길이와 리필 패드 규격을 확인하세요.', '/cleanloop/images/selection-comet-spray-mop.png', '4.7', '후기 35,320개', TRUE, 'https://www.coupang.com/vp/products/6113657232', 'published', 22),
    ('c1000000-0000-0000-0000-000000000014', 'scotchbrite-static-cloth', 'product', '바닥/먼지', '3M 스카치브라이트 정전기 청소포', '청소포', '대형 30매 약 5,800원부터', '11번가/다나와', '정전기 유도 코팅 부직포로 바닥의 먼지와 머리카락을 흡착하는 건식 또는 물걸레 겸용 리필형 청소포', '물걸레질 전 마른 먼지를 먼저 제거하거나 반려동물 털을 매일 가볍게 훔칠 때', '밀대 헤드 규격과 표준형/대형 사이즈를 확인하세요.', '/cleanloop/images/selection-scotchbrite-static-cloth.png', '확인 안 됨', '판매처별 상이', FALSE, 'https://prod.danawa.com/info/?pcode=3864540', 'published', 23),
    ('c1000000-0000-0000-0000-000000000015', 'cleaninglab-homeclean', 'service', '바닥/먼지', '청소연구소 방문청소 서비스', '방문청소', '예약 화면 확인', '청소연구소', '교육받은 파트너가 방문해 집 전체 또는 특정 공간을 청소해주는 매칭형 방문청소 플랫폼', '대청소 시간과 체력이 부족하거나 반려동물이 있어 바닥 먼지 관리가 잦은 가정', '매니저별 품질 편차 후기가 있어 선호 매니저 지정 예약이 도움이 됩니다.', '/cleanloop/images/selection-cleaninglab-homeclean.png', '확인 안 됨', '공식 후기 다수', FALSE, 'https://www.cleaninglab.co.kr/office_clean', 'published', 24),
    ('c1000000-0000-0000-0000-000000000016', 'miso-aircon-doc', 'service', '계절/가전', '미소 스탠드형 에어컨 완전분해 청소', '에어컨청소', '94,500원부터', '미소', '브랜드 관계없이 스탠드형 에어컨을 분해해 전문 장비로 세척하는 방문형 가전 청소 서비스', '여름철 가동 전 곰팡이, 냄새 제거와 냉방 효율 회복이 필요할 때', '벽걸이, 스탠드, 시스템 기종을 정확히 구분하고 성수기 예약 지연 가능성을 고려하세요.', '/cleanloop/images/selection-miso-aircon-doc.png', '확인 안 됨', '앱 예약 기준', TRUE, 'https://miso.kr/appclean', 'published', 25),
    ('c1000000-0000-0000-0000-000000000017', 'winix-dehumidifier-12l', 'product', '계절/가전', '위닉스 뽀송 제습기 12L', '제습기', '약 20만원 초중반대', '쿠팡/다나와', '일일 제습량 12L, 물통 3.0L급 가정용 제습기로 장마철 실내 습도와 곰팡이 냄새 관리에 좋습니다.', '장마철과 여름철 실내 눅눅함을 줄이고 싶은 원룸부터 중형 평수 가정', '물통 용량, 소비전력, 소음 수준을 확인하세요.', '/cleanloop/images/selection-winix-dehumidifier.png', '확인 안 됨', '스테디셀러 언급', FALSE, 'https://prod.danawa.com/info/?pcode=19395899', 'published', 26),
    ('c1000000-0000-0000-0000-000000000018', 'moolmukneunhama-closet', 'product', '계절/가전', '옥시 물먹는하마 옷장용 습기제거제', '제습제', '약 11,900원', 'GS SHOP/쿠팡', '옷장과 서랍장 같은 밀폐 공간에 넣는 1회용 습기제거제로 곰팡이와 냄새 발생을 줄이는 계절 보조용품', '장마철이나 환절기 옷장 속 눅눅함과 곰팡이 냄새가 걱정될 때', '습기를 다 흡수하면 교체가 필요하며 방충 목적이면 별도 제품이 필요합니다.', '/cleanloop/images/selection-moolmukneunhama-closet.png', '4.6', '후기 1,561개', FALSE, 'http://m.gsshop.com/', 'published', 27),
    ('c1000000-0000-0000-0000-000000000019', 'saioang-cat-litter-deodorizer', 'product', '반려동물', '세이오앙 고양이 모래 탈취제 1000ml', '모래탈취', '약 12,000원', '비마이펫', '천연 야자나무 활성탄 기반 고양이 모래 전용 탈취제로 기존 모래에 섞어 냄새를 흡착합니다.', '고양이 화장실 냄새가 반복적으로 신경 쓰이지만 모래 자체를 바꾸긴 번거로운 집', '개체별 기호성 차이가 있을 수 있어 소량 테스트가 좋습니다.', '/cleanloop/images/selection-saioang-cat-litter-deodorizer.png', '5.0', '후기 11개', TRUE, 'https://store.bemypet.kr/', 'published', 28),
    ('c1000000-0000-0000-0000-000000000020', 'urine-off-puppy', 'product', '반려동물', '유린오프 독 앤 퍼피 소변냄새제거제 500ml', '소변냄새', '약 22,500원', '피그독/도그팡', '효소와 박테리아로 소변의 요산 결정까지 분해해 냄새 근원을 제거하는 반려동물 전용 클리너', '배변 실수가 잦은 반려동물 가정에서 마른 소변 얼룩과 냄새가 섬유류에 남았을 때', '판매처별 재고 상황과 원단, 색상 변색 여부를 테스트하세요.', '/cleanloop/images/selection-urine-off-puppy.png', '5.0', '후기 5개', FALSE, 'https://pigdog.co.kr/', 'published', 29),
    ('c1000000-0000-0000-0000-000000000021', 'easy-safe-pet-spray', 'product', '반려동물', '이지세이프펫 반려동물 살균 탈취제 스프레이', '살균탈취', '약 2,960~45,500원', '심콩스토어', '자연유래 미네랄 성분 기반의 무색, 무취 살균 탈취 스프레이로 반려동물 냄새 관리에 씁니다.', '반려동물과 아이가 함께 있어 저자극 살균과 탈취가 필요한 상황', '무독성, 저자극은 판매처 설명이므로 전 성분표를 별도로 확인하세요.', '/cleanloop/images/selection-easy-safe-pet-spray.png', '확인 안 됨', '개별 후기 8건', FALSE, 'https://simkongcat.com/', 'published', 30),
    ('c1000000-0000-0000-0000-000000000022', 'daiso-recycle-bin', 'product', '소모품', '다이소 봉투 거치 분리수거함 48L', '분리수거함', '약 5,000원', '다이소몰', '종량제봉투와 분리수거 봉투를 뚜껑 안쪽에 거치해 쓰는 48L 용량 정리함', '베란다나 다용도실에서 종량제봉투와 분리수거 봉투가 흐트러지기 쉬운 가구', '사용하는 봉투 규격과 설치 공간 크기를 확인하세요.', '/cleanloop/images/selection-daiso-recycle-bin.png', '4.8', '후기 1,252개', FALSE, 'https://www.daisomall.co.kr/', 'published', 31),
    ('c1000000-0000-0000-0000-000000000023', 'daiso-microfiber-cloth', 'product', '소모품', '다이소 뽑아 쓰는 다회용 극세사 걸레 12매', '극세사걸레', '약 2,000원', '다이소몰', '티슈처럼 한 장씩 뽑아 쓰고 세탁 후 재사용 가능한 극세사 걸레 12매 세트', '주방, 거실, 욕실의 먼지와 물기를 매일 가볍고 위생적으로 닦고 싶을 때', '극세사 특성상 단독 세탁하고 고온, 표백제, 섬유유연제는 피하세요.', '/cleanloop/images/selection-daiso-microfiber-cloth.png', '4.7', '후기 453개', FALSE, 'https://www.daisomall.co.kr/', 'published', 32),
    ('c1000000-0000-0000-0000-000000000024', 'tamsaa-nitrile-gloves', 'product', '소모품', '탐사 니트릴 장갑 블랙 200개입', '청소장갑', '약 15,990원', '쿠팡/다나와', '청소, 설거지, 잡일 시 손을 보호하는 라텍스 프리 블랙 니트릴 일회용 장갑 200개입', '화장실이나 주방에서 세제와 이물질을 직접 만지지 않고 청소해야 할 때', '라텍스 알레르기 여부와 사이즈를 확인하세요.', '/cleanloop/images/selection-tamsaa-nitrile-gloves.png', '확인 안 됨', '판매처별 상이', FALSE, 'https://prod.danawa.com/info/?pcode=31663085', 'published', 33);
