INSERT INTO community_posts (id, type, title, tag, body, image_url, helpful_count, comments_count, answers_count, saved_count, status, is_recommended, created_at) VALUES
    ('e1000000-0000-0000-0000-000000000001', 'tips', '수건 냄새는 세탁조와 건조 습관을 같이 봅니다', '세탁', '수건과 의류 냄새는 세탁조 곰팡이와 불완전 건조에서 시작되는 경우가 많습니다. 수건은 단독 세탁하고 세탁 직후 바로 건조하세요. 세탁조는 통돌이 월 1회, 드럼 월 1~2회 청소하고 침구는 60도 안팎의 물로 1~2주마다 세탁하는 흐름이 좋습니다.', '/cleanloop/images/tip-laundry.png', 47, 0, 0, 11, 'published', FALSE, DATEADD('DAY', -21, CURRENT_TIMESTAMP)),
    ('e1000000-0000-0000-0000-000000000002', 'tips', '욕실 물때와 곰팡이는 원인별로 다르게 지웁니다', '욕실', '샤워 직후 물기를 제거하고 30분 이상 환기하면 곰팡이 번식 속도를 늦출 수 있습니다. 분홍 물때는 세라티아균이라 살균이 필요하고, 실리콘 틈 검은 곰팡이는 락스를 적신 휴지를 밀착해 두는 방식이 효과적입니다.', '/cleanloop/images/tip-bath.png', 46, 0, 0, 10, 'published', FALSE, DATEADD('DAY', -22, CURRENT_TIMESTAMP)),
    ('e1000000-0000-0000-0000-000000000003', 'tips', '주방 기름때와 도마 위생은 순서가 핵심입니다', '주방', '기름때는 따뜻한 물과 주방세제로 먼저 불리고 베이킹소다와 식초는 순서대로 씁니다. 도마는 육류, 생선, 채소용을 나누는 편이 좋고 나무 도마는 소금과 레몬으로 냄새를 줄인 뒤 세워 말리세요.', '/cleanloop/images/tip-kitchen.png', 45, 0, 0, 9, 'published', FALSE, DATEADD('DAY', -23, CURRENT_TIMESTAMP)),
    ('e1000000-0000-0000-0000-000000000004', 'tips', '음식물쓰레기 악취는 수분 제거가 먼저입니다', '수거', '음식물쓰레기 냄새는 수분 관리가 핵심입니다. 신문지나 거름망으로 물기를 빼고 소량이라도 자주 배출하세요. 냉동 보관은 세균이 사멸하지 않아 권장되지 않으며 베이킹소다와 식초는 보조 탈취 수단으로 쓰면 좋습니다.', '/cleanloop/images/tip-trash.png', 44, 0, 0, 8, 'published', FALSE, DATEADD('DAY', -24, CURRENT_TIMESTAMP)),
    ('e1000000-0000-0000-0000-000000000005', 'tips', '바닥은 먼지 제거 후 물걸레질해야 합니다', '바닥', '먼지 위에 물을 얹으면 먼지가 뭉쳐 다시 달라붙습니다. 정전기포나 청소기로 마른 먼지를 먼저 걷고 물걸레질하세요. 청소 순서는 위에서 아래로, 깨끗한 구역에서 더러운 구역으로 이동하는 편이 효율적입니다.', '/cleanloop/images/tip-floor.png', 43, 0, 0, 7, 'published', FALSE, DATEADD('DAY', -25, CURRENT_TIMESTAMP)),
    ('e1000000-0000-0000-0000-000000000006', 'tips', '에어컨 냄새는 필터보다 건조 루틴이 중요합니다', '계절', '에어컨 필터는 2주에 한 번 청소하고 사용 후 송풍 모드로 내부를 말리는 습관이 필요합니다. 냄새가 심하면 냉방과 송풍을 조합해 내부 응축수를 만들고 건조시키며, 송풍팬 깊숙한 곰팡이는 분해 세척이 필요할 수 있습니다.', '/cleanloop/images/tip-season.png', 42, 0, 0, 6, 'published', FALSE, DATEADD('DAY', -26, CURRENT_TIMESTAMP)),
    ('e1000000-0000-0000-0000-000000000007', 'tips', '반려동물 냄새는 즉시 처리와 침구 관리가 좌우합니다', '반려', '배변 실수는 장판에 스며들기 전에 바로 닦고, 소변 부위는 수분을 충분히 제거한 뒤 베이킹소다로 냄새를 흡수시키세요. 침구와 쿠션은 최소 월 2회 세탁하고 화장실과 배변패드는 자주 갈아주는 편이 좋습니다.', '/cleanloop/images/tip-pet.png', 41, 0, 0, 5, 'published', FALSE, DATEADD('DAY', -27, CURRENT_TIMESTAMP)),
    ('e1000000-0000-0000-0000-000000000008', 'tips', '스펀지와 걸레는 정기 교체가 청소의 일부입니다', '소모품', '주방 스펀지와 행주는 세균 밀도가 높은 물건이라 주 1회 교체가 권장됩니다. 교체 전에는 전자레인지나 식기세척기 고온 코스로 살균하고, 걸레와 로봇청소기 패드도 구역별로 나누고 정기 교체하세요.', '/cleanloop/images/tip-supplies.png', 40, 0, 0, 4, 'published', FALSE, DATEADD('DAY', -28, CURRENT_TIMESTAMP)),
    ('e1000000-0000-0000-0000-000000000101', 'qa', '수건을 매번 빨아도 쉰내가 나요. 세제를 바꿔야 하나요?', '세탁', '세탁을 했는데도 수건에서 퀴퀴한 냄새가 나고 세제나 섬유유연제를 바꿔도 며칠 뒤 다시 냄새가 올라오는 상황입니다.', '/cleanloop/images/qna-washer-gasket-mold.png', 27, 0, 2, 7, 'published', FALSE, DATEADD('DAY', -29, CURRENT_TIMESTAMP)),
    ('e1000000-0000-0000-0000-000000000102', 'qa', '침구는 얼마나 자주, 어떻게 세탁해야 진드기가 줄어드나요?', '세탁', '알레르기 비염이나 피부 트러블이 있을 때 침구 관리 주기와 세탁 방법을 묻는 상황입니다.', NULL, 26, 0, 2, 7, 'published', FALSE, DATEADD('DAY', -30, CURRENT_TIMESTAMP)),
    ('e1000000-0000-0000-0000-000000000103', 'qa', '욕실 벽에 자꾸 생기는 분홍색 얼룩은 곰팡이인가요?', '욕실', '검은 곰팡이와 달리 분홍빛 얼룩이 욕조나 세면대 주변에 생겨 무엇인지 궁금한 상황입니다.', '/cleanloop/images/qna-pink-slime.png', 25, 0, 2, 6, 'published', FALSE, DATEADD('DAY', -31, CURRENT_TIMESTAMP)),
    ('e1000000-0000-0000-0000-000000000104', 'qa', '실리콘 틈새 검은 곰팡이는 문질러도 안 지워지는데 방법이 없나요?', '욕실', '일반 세정제와 솔로 문질러도 실리콘 틈의 검은 자국이 남아 재청소를 반복하는 상황입니다.', '/cleanloop/images/qna-mold-paper-towel.png', 24, 0, 2, 6, 'published', FALSE, DATEADD('DAY', -32, CURRENT_TIMESTAMP)),
    ('e1000000-0000-0000-0000-000000000105', 'qa', '나무 도마에서 나는 비린내, 세제로 씻어도 안 없어져요.', '주방', '생선이나 고기를 손질한 뒤 나무 도마에 냄새가 배어 세제로 여러 번 씻어도 남아있는 상황입니다.', '/cleanloop/images/qna-cutting-board-lemon-salt.png', 23, 0, 2, 6, 'published', FALSE, DATEADD('DAY', -33, CURRENT_TIMESTAMP)),
    ('e1000000-0000-0000-0000-000000000106', 'qa', '도마를 육류/채소용으로 꼭 나눠야 할까요? 하나로 써도 되나요?', '주방', '도마를 여러 개 두기 번거로워 하나로 모든 식재료를 손질해도 괜찮은지 묻는 상황입니다.', NULL, 22, 0, 2, 5, 'published', FALSE, DATEADD('DAY', -34, CURRENT_TIMESTAMP)),
    ('e1000000-0000-0000-0000-000000000107', 'qa', '음식물쓰레기, 냉동실에 얼려서 모아 버려도 괜찮나요?', '수거', '음식물쓰레기를 자주 배출하기 번거로워 냉동실에 모아뒀다가 한 번에 버려도 되는지 묻는 상황입니다.', NULL, 21, 0, 2, 5, 'published', FALSE, DATEADD('DAY', -35, CURRENT_TIMESTAMP)),
    ('e1000000-0000-0000-0000-000000000108', 'qa', '음식물쓰레기 봉투를 열 때마다 냄새가 훅 올라와요. 줄일 방법이 있나요?', '수거', '음식물쓰레기 봉투를 여닫을 때마다 악취가 올라와 스트레스를 받는 상황입니다.', NULL, 20, 0, 2, 5, 'published', FALSE, DATEADD('DAY', -36, CURRENT_TIMESTAMP)),
    ('e1000000-0000-0000-0000-000000000109', 'qa', '청소기와 물걸레, 어떤 걸 먼저 해야 더 깨끗해지나요?', '바닥', '청소기와 물걸레 순서를 바꿔가며 청소해도 어느 쪽이 더 효율적인지 헷갈리는 상황입니다.', NULL, 19, 0, 2, 4, 'published', FALSE, DATEADD('DAY', -37, CURRENT_TIMESTAMP)),
    ('e1000000-0000-0000-0000-000000000110', 'qa', '바닥 재질에 따라 청소 세제도 다르게 써야 하나요?', '바닥', '장판과 타일이 섞인 집에서 같은 세제를 써도 되는지 묻는 상황입니다.', NULL, 18, 0, 2, 4, 'published', FALSE, DATEADD('DAY', -38, CURRENT_TIMESTAMP)),
    ('e1000000-0000-0000-0000-000000000111', 'qa', '에어컨 필터만 청소하면 곰팡이 냄새가 없어지나요?', '계절', '필터를 닦아도 에어컨을 켤 때 곰팡이 냄새가 계속 나는 상황입니다.', NULL, 17, 0, 2, 4, 'published', FALSE, DATEADD('DAY', -39, CURRENT_TIMESTAMP)),
    ('e1000000-0000-0000-0000-000000000112', 'qa', '에어컨 청소는 얼마나 자주 해야 하나요?', '계절', '여름철 처음 켤 때 냄새가 심해 관리 주기를 미리 알고 싶은 상황입니다.', NULL, 16, 0, 2, 3, 'published', FALSE, DATEADD('DAY', -40, CURRENT_TIMESTAMP)),
    ('e1000000-0000-0000-0000-000000000113', 'qa', '강아지 오줌 자국을 닦았는데 시간이 지나면 냄새가 다시 올라와요.', '반려', '눈에 보이는 자국은 바로 닦았는데도 하루 이틀 뒤 냄새가 다시 나는 상황입니다.', NULL, 15, 0, 2, 3, 'published', FALSE, DATEADD('DAY', -41, CURRENT_TIMESTAMP)),
    ('e1000000-0000-0000-0000-000000000114', 'qa', '반려동물 냄새 없애려면 방향제만 뿌려도 되나요?', '반려', '손님이 오기 전 방향제로 냄새만 가리려는 경우 근본 해결법을 묻는 상황입니다.', NULL, 14, 0, 2, 3, 'published', FALSE, DATEADD('DAY', -42, CURRENT_TIMESTAMP)),
    ('e1000000-0000-0000-0000-000000000115', 'qa', '주방 스펀지, 냄새 나기 전까지 계속 써도 되나요?', '소모품', '스펀지가 멀쩡해 보여 냄새가 나기 전까지 계속 써도 되는지 묻는 상황입니다.', NULL, 13, 0, 2, 2, 'published', FALSE, DATEADD('DAY', -43, CURRENT_TIMESTAMP)),
    ('e1000000-0000-0000-0000-000000000116', 'qa', '걸레는 몇 개나 준비해야 하고, 얼마나 자주 바꿔야 하나요?', '소모품', '걸레 하나로 온 집을 다 닦아도 되는지, 따로 준비해야 하는지 묻는 상황입니다.', NULL, 12, 0, 2, 2, 'published', FALSE, DATEADD('DAY', -44, CURRENT_TIMESTAMP));
INSERT INTO community_comments (id, post_id, user_id, body, created_at) VALUES
    ('f1000000-0000-0000-0000-000000000001', 'e1000000-0000-0000-0000-000000000101', 'a0000000-0000-0000-0000-000000000001', '세제보다 세탁기 내부 곰팡이를 먼저 의심하세요. 통돌이는 월 1회, 드럼은 월 1~2회 세탁조 클리너로 청소하고 고무 패킹 안쪽 물기를 닦아주세요.', DATEADD('DAY', -29, CURRENT_TIMESTAMP)),
    ('f1000000-0000-0000-0000-000000000002', 'e1000000-0000-0000-0000-000000000101', 'a0000000-0000-0000-0000-000000000001', '수건은 다른 빨래와 섞지 말고 단독 세탁한 뒤 바로 널어 완전히 건조하세요. 젖은 상태로 방치되는 시간이 길수록 냄새가 다시 올라옵니다.', DATEADD('DAY', -29, CURRENT_TIMESTAMP)),
    ('f1000000-0000-0000-0000-000000000003', 'e1000000-0000-0000-0000-000000000102', 'a0000000-0000-0000-0000-000000000001', '이불과 베개커버는 60도 안팎의 뜨거운 물로 1~2주에 한 번 세탁하고 햇볕에 완전히 말리는 편이 좋습니다.', DATEADD('DAY', -30, CURRENT_TIMESTAMP)),
    ('f1000000-0000-0000-0000-000000000004', 'e1000000-0000-0000-0000-000000000102', 'a0000000-0000-0000-0000-000000000001', '매트리스처럼 통째로 세탁하기 어려운 물건은 베이킹소다를 뿌려 1~2시간 둔 뒤 청소기로 흡입하면 흡습과 탈취에 도움이 됩니다.', DATEADD('DAY', -30, CURRENT_TIMESTAMP)),
    ('f1000000-0000-0000-0000-000000000005', 'e1000000-0000-0000-0000-000000000103', 'a0000000-0000-0000-0000-000000000001', '분홍 얼룩은 곰팡이가 아니라 세라티아 마르세센스라는 박테리아인 경우가 많습니다. 습한 욕조와 샤워기 주변에 잘 생겨 발견 즉시 제거하는 편이 좋습니다.', DATEADD('DAY', -31, CURRENT_TIMESTAMP)),
    ('f1000000-0000-0000-0000-000000000006', 'e1000000-0000-0000-0000-000000000103', 'a0000000-0000-0000-0000-000000000001', '락스나 식초 희석액으로 표면을 닦아내고, 청소 후에는 물기를 제거하고 환기해 재발 조건을 줄이세요.', DATEADD('DAY', -31, CURRENT_TIMESTAMP)),
    ('f1000000-0000-0000-0000-000000000007', 'e1000000-0000-0000-0000-000000000104', 'a0000000-0000-0000-0000-000000000001', '락스를 적신 휴지를 곰팡이 부위에 붙이고 1~2시간, 심하면 반나절 정도 둔 뒤 떼어내면 밀착 시간이 확보되어 효과적입니다. 반드시 환기하고 마스크를 착용하세요.', DATEADD('DAY', -32, CURRENT_TIMESTAMP)),
    ('f1000000-0000-0000-0000-000000000008', 'e1000000-0000-0000-0000-000000000104', 'a0000000-0000-0000-0000-000000000001', '재발을 줄이려면 샤워 후 부스나 커튼을 열어 내부를 완전히 말리고 실리콘 주변 물기를 닦아주세요.', DATEADD('DAY', -32, CURRENT_TIMESTAMP)),
    ('f1000000-0000-0000-0000-000000000009', 'e1000000-0000-0000-0000-000000000105', 'a0000000-0000-0000-0000-000000000001', '나무는 다공성 재질이라 세제가 틈새에 스며들 수 있습니다. 굵은 소금을 뿌리고 레몬 반쪽으로 문지른 뒤 미지근한 물로 헹궈보세요.', DATEADD('DAY', -33, CURRENT_TIMESTAMP)),
    ('f1000000-0000-0000-0000-000000000010', 'e1000000-0000-0000-0000-000000000105', 'a0000000-0000-0000-0000-000000000001', '세척 후에는 눕혀두지 말고 세워서 완전히 건조하세요. 축축한 상태로 보관하면 세균 번식과 냄새 재발 가능성이 커집니다.', DATEADD('DAY', -33, CURRENT_TIMESTAMP)),
    ('f1000000-0000-0000-0000-000000000011', 'e1000000-0000-0000-0000-000000000106', 'a0000000-0000-0000-0000-000000000001', '가능하면 나누는 것을 권장합니다. 같은 도마로 여러 식재료를 손질하면 교차오염 위험이 커집니다.', DATEADD('DAY', -34, CURRENT_TIMESTAMP)),
    ('f1000000-0000-0000-0000-000000000012', 'e1000000-0000-0000-0000-000000000106', 'a0000000-0000-0000-0000-000000000001', '도마를 하나만 써야 한다면 육류와 생선을 손질한 직후 뜨거운 물이나 식초로 살균한 뒤 다음 재료를 손질하세요.', DATEADD('DAY', -34, CURRENT_TIMESTAMP)),
    ('f1000000-0000-0000-0000-000000000013', 'e1000000-0000-0000-0000-000000000107', 'a0000000-0000-0000-0000-000000000001', '권장되지 않습니다. 냉동실에서도 살아남는 저온성 세균이 있어 위생상 안전한 보관법으로 보기 어렵습니다.', DATEADD('DAY', -35, CURRENT_TIMESTAMP)),
    ('f1000000-0000-0000-0000-000000000014', 'e1000000-0000-0000-0000-000000000107', 'a0000000-0000-0000-0000-000000000001', '소량이라도 자주 배출하는 것이 가장 안전하고, 부득이하게 모아야 한다면 물기를 최대한 제거한 뒤 밀봉하세요.', DATEADD('DAY', -35, CURRENT_TIMESTAMP)),
    ('f1000000-0000-0000-0000-000000000015', 'e1000000-0000-0000-0000-000000000108', 'a0000000-0000-0000-0000-000000000001', '버릴 때마다 베이킹소다를 2~3스푼 뿌리면 산성 냄새를 알칼리 성분이 중화하는 데 도움이 됩니다.', DATEADD('DAY', -36, CURRENT_TIMESTAMP)),
    ('f1000000-0000-0000-0000-000000000016', 'e1000000-0000-0000-0000-000000000108', 'a0000000-0000-0000-0000-000000000001', '식초를 분무기에 담아 가볍게 뿌리면 살균과 탈취를 함께 보조할 수 있습니다. 단, 밀폐 전 수분은 최대한 줄이세요.', DATEADD('DAY', -36, CURRENT_TIMESTAMP)),
    ('f1000000-0000-0000-0000-000000000017', 'e1000000-0000-0000-0000-000000000109', 'a0000000-0000-0000-0000-000000000001', '마른 청소를 먼저 하고 물걸레를 나중에 해야 합니다. 먼지 위에 바로 물을 얹으면 먼지가 뭉쳐 바닥에 다시 달라붙습니다.', DATEADD('DAY', -37, CURRENT_TIMESTAMP)),
    ('f1000000-0000-0000-0000-000000000018', 'e1000000-0000-0000-0000-000000000109', 'a0000000-0000-0000-0000-000000000001', '정전기포나 청소기로 머리카락과 큰 먼지를 먼저 걷어내면 물걸레 자국과 재오염이 줄어듭니다.', DATEADD('DAY', -37, CURRENT_TIMESTAMP)),
    ('f1000000-0000-0000-0000-000000000019', 'e1000000-0000-0000-0000-000000000110', 'a0000000-0000-0000-0000-000000000001', '장판과 비닐 바닥에는 락스 같은 염소계 표백제가 변색이나 코팅 손상을 만들 수 있어 중성세제가 안전합니다.', DATEADD('DAY', -38, CURRENT_TIMESTAMP)),
    ('f1000000-0000-0000-0000-000000000020', 'e1000000-0000-0000-0000-000000000110', 'a0000000-0000-0000-0000-000000000001', '타일과 대리석 줄눈은 따뜻한 물과 중성세제 또는 스팀청소기를 쓰면 깊은 오염 제거에 도움이 됩니다.', DATEADD('DAY', -38, CURRENT_TIMESTAMP)),
    ('f1000000-0000-0000-0000-000000000021', 'e1000000-0000-0000-0000-000000000111', 'a0000000-0000-0000-0000-000000000001', '필터 청소만으로는 부족할 수 있습니다. 증발기와 송풍팬 깊숙한 곰팡이는 필터와 별개 문제입니다.', DATEADD('DAY', -39, CURRENT_TIMESTAMP)),
    ('f1000000-0000-0000-0000-000000000022', 'e1000000-0000-0000-0000-000000000111', 'a0000000-0000-0000-0000-000000000001', '사용 후 10~20분 이상 송풍 모드로 내부를 건조시키고, 냄새가 심하면 전문가 분해 세척을 고려하세요.', DATEADD('DAY', -39, CURRENT_TIMESTAMP)),
    ('f1000000-0000-0000-0000-000000000023', 'e1000000-0000-0000-0000-000000000112', 'a0000000-0000-0000-0000-000000000001', '필터는 2주에 한 번 정도 청소하는 것이 권장됩니다.', DATEADD('DAY', -40, CURRENT_TIMESTAMP)),
    ('f1000000-0000-0000-0000-000000000024', 'e1000000-0000-0000-0000-000000000112', 'a0000000-0000-0000-0000-000000000001', '냄새가 심할 때는 냉방 1시간과 송풍 1시간 루틴을 주 2~3회, 2주 정도 반복하면 완화에 도움이 될 수 있습니다.', DATEADD('DAY', -40, CURRENT_TIMESTAMP)),
    ('f1000000-0000-0000-0000-000000000025', 'e1000000-0000-0000-0000-000000000113', 'a0000000-0000-0000-0000-000000000001', '눈에 보이는 자국보다 소변이 더 넓게 퍼져 있을 수 있어 얼룩 부위보다 조금 더 넓게 닦아야 합니다.', DATEADD('DAY', -41, CURRENT_TIMESTAMP)),
    ('f1000000-0000-0000-0000-000000000026', 'e1000000-0000-0000-0000-000000000113', 'a0000000-0000-0000-0000-000000000001', '수분을 충분히 닦아낸 뒤 베이킹소다를 표면이 덮이도록 뿌려 남은 습기와 냄새를 흡수시키세요.', DATEADD('DAY', -41, CURRENT_TIMESTAMP)),
    ('f1000000-0000-0000-0000-000000000027', 'e1000000-0000-0000-0000-000000000114', 'a0000000-0000-0000-0000-000000000001', '방향제는 임시방편입니다. 배변 직후 즉시 청소하고 침구와 쿠션을 최소 월 2회 세탁해야 냄새가 줄어듭니다.', DATEADD('DAY', -42, CURRENT_TIMESTAMP)),
    ('f1000000-0000-0000-0000-000000000028', 'e1000000-0000-0000-0000-000000000114', 'a0000000-0000-0000-0000-000000000001', '화장실이나 배변판, 모래도 자주 갈아주세요. 화장실이 더러우면 다른 곳에 배변해 냄새 관리가 어려워질 수 있습니다.', DATEADD('DAY', -42, CURRENT_TIMESTAMP)),
    ('f1000000-0000-0000-0000-000000000029', 'e1000000-0000-0000-0000-000000000115', 'a0000000-0000-0000-0000-000000000001', '권장되지 않습니다. 주방 스펀지와 행주는 세균 밀도가 높아 주 1회 교체가 권장됩니다.', DATEADD('DAY', -43, CURRENT_TIMESTAMP)),
    ('f1000000-0000-0000-0000-000000000030', 'e1000000-0000-0000-0000-000000000115', 'a0000000-0000-0000-0000-000000000001', '교체 전까지는 젖은 스펀지를 전자레인지에 1분간 돌리거나 식기세척기 고온 코스로 살균하면 세균을 줄일 수 있습니다.', DATEADD('DAY', -43, CURRENT_TIMESTAMP)),
    ('f1000000-0000-0000-0000-000000000031', 'e1000000-0000-0000-0000-000000000116', 'a0000000-0000-0000-0000-000000000001', '최소 2장 이상을 준비해 주방용과 거실/방용을 나누면 얼룩과 교차오염을 줄일 수 있습니다.', DATEADD('DAY', -44, CURRENT_TIMESTAMP)),
    ('f1000000-0000-0000-0000-000000000032', 'e1000000-0000-0000-0000-000000000116', 'a0000000-0000-0000-0000-000000000001', '로봇청소기 걸레패드와 필터도 습기가 남으면 곰팡이와 쉰내가 생기므로 1~3개월 주기로 점검하고 교체하세요.', DATEADD('DAY', -44, CURRENT_TIMESTAMP));
